css:
.loader {
  position: relative;
  display: inline-block;
  width: 70px;
  height: 54px;
  color: #6366f1;
}
.loader i {
  position: absolute;
  width: 10px;
  height: 10px;
  border-radius: 3px;
  background: currentColor;
  animation: confetti 1s ease-in-out infinite;
}
.loader i:nth-child(1) { left: 4px; top: 34px; }
.loader i:nth-child(2) { left: 18px; top: 14px; animation-delay: .1s; }
.loader i:nth-child(3) { left: 34px; top: 30px; animation-delay: .2s; }
.loader i:nth-child(4) { left: 49px; top: 10px; animation-delay: .3s; }
.loader i:nth-child(5) { left: 60px; top: 36px; animation-delay: .4s; }
@keyframes confetti {
  0%, 100% { transform: translateY(0) rotate(0deg); opacity: .35; }
  50% { transform: translateY(-12px) rotate(90deg); opacity: 1; }
}
